module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

reg [15:0] a, b;
reg [31:0] product;
reg [4:0] count;
reg done_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a <= 0;
        b <= 0;
        product <= 0;
        count <= 0;
        done_reg <= 0;
    end
    else if (start) begin
        if (count == 0) begin
            a <= ain;
            b <= bin;
        end
        else if (count < 17) begin
            if (a[count-1]) begin
                product <= product + (b << (count-1));
            end
            count <= count + 1;
        end
        else begin
            done_reg <= 1;
            count <= 0;
        end
    end
    else begin
        done_reg <= 0;
    end
end

assign yout = product;
assign done = done_reg;

endmodule
